import{_ as e,o as l,c as d,ag as a}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse('{"title":"함수 | Dotfiles (KO)","titleTemplate":":title","description":"터미널 경험을 향상시키는 셸 함수. API 테스팅, 파일 관리, 시스템 작업 등을 위한 유틸리티.","frontmatter":{"title":"함수 | Dotfiles","description":"터미널 경험을 향상시키는 셸 함수. API 테스팅, 파일 관리, 시스템 작업 등을 위한 유틸리티.","lang":"ko-KR","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"함수 preview","canonical":"/ko/functions/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"함수","pageType":"docs","schemaType":"WebPage","metaTitle":"함수 - Dotfiles (KR)","permalink":"/ko/functions/","meta":[{"name":"keywords","content":"functions, shell, bash, zsh, dotfiles, productivity, utilities, api, file, system"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"터미널 경험을 향상시키는 셸 함수. API 테스팅, 파일 관리, 시스템 작업 등을 위한 유틸리티."},{"name":"twitter:title","content":"함수 - Dotfiles"},{"name":"og:title","content":"함수 - Dotfiles"},{"name":"og:description","content":"터미널 경험을 향상시키는 셸 함수. API 테스팅, 파일 관리, 시스템 작업 등을 위한 유틸리티."},{"name":"og:image:alt","content":"Dotfiles - 셸 라이프에 맞게 간단하게 설계됨"},{"name":"og:locale","content":"ko_KR"}]},"headers":[],"relativePath":"ko/functions/index.md","filePath":"ko/functions/index.md","lastUpdated":1773010926000}'),o={name:"ko/functions/index.md"};function i(s,t,n,c,r,f){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="함수" tabindex="-1">함수 <a class="header-anchor" href="#함수" aria-label="Permalink to &quot;함수&quot;">​</a></h1><p>macOS, Linux, Windows에서 생산성을 향상시키는 셸 유틸리티.</p><h2 id="발견하기" tabindex="-1">발견하기 <a class="header-anchor" href="#발견하기" aria-label="Permalink to &quot;발견하기&quot;">​</a></h2><p>함수는 개별 <code>.sh</code> 파일로 정의됩니다. <code>chezmoi apply</code> 중에 <code>~/.config/shell/functions.sh</code>로 집계되어 셸에서 소스됩니다.</p><h2 id="시작하기" tabindex="-1">시작하기 <a class="header-anchor" href="#시작하기" aria-label="Permalink to &quot;시작하기&quot;">​</a></h2><h3 id="함수-추가" tabindex="-1">함수 추가 <a class="header-anchor" href="#함수-추가" aria-label="Permalink to &quot;함수 추가&quot;">​</a></h3><ol><li>새 <code>.sh</code> 파일을 생성합니다 (예: <code>myfunc.sh</code>)</li><li>함수 정의를 추가합니다</li><li>변경 사항을 적용합니다:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chezmoi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span></span></code></pre></div></li></ol><h2 id="참조" tabindex="-1">참조 <a class="header-anchor" href="#참조" aria-label="Permalink to &quot;참조&quot;">​</a></h2><h3 id="api-테스팅" tabindex="-1">API 테스팅 <a class="header-anchor" href="#api-테스팅" aria-label="Permalink to &quot;API 테스팅&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">함수</th><th style="text-align:left;">설명</th><th style="text-align:left;">사용법</th></tr></thead><tbody><tr><td style="text-align:left;"><code>apihealth</code></td><td style="text-align:left;">하나 이상의 API 상태 확인</td><td style="text-align:left;"><code>apihealth [OPTIONS] URL [URL ...]</code></td></tr><tr><td style="text-align:left;"><code>apilatency</code></td><td style="text-align:left;">API 응답 시간 모니터링</td><td style="text-align:left;"><code>apilatency URL [COUNT] [INTERVAL]</code></td></tr><tr><td style="text-align:left;"><code>apiload</code></td><td style="text-align:left;">기본 부하 테스트 수행</td><td style="text-align:left;"><code>apiload URL [REQUESTS] [DELAY]</code></td></tr><tr><td style="text-align:left;"><code>httpdebug</code></td><td style="text-align:left;">타이밍과 함께 HTTP 요청 디버그</td><td style="text-align:left;"><code>httpdebug [options] [url]</code></td></tr></tbody></table><h3 id="http-유틸리티" tabindex="-1">HTTP 유틸리티 <a class="header-anchor" href="#http-유틸리티" aria-label="Permalink to &quot;HTTP 유틸리티&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">함수</th><th style="text-align:left;">설명</th><th style="text-align:left;">사용법</th></tr></thead><tbody><tr><td style="text-align:left;"><code>curlheader</code></td><td style="text-align:left;">HTTP 헤더 보기</td><td style="text-align:left;"><code>curlheader [header] [url]</code></td></tr><tr><td style="text-align:left;"><code>curlstatus</code></td><td style="text-align:left;">HTTP 상태 코드 확인</td><td style="text-align:left;"><code>curlstatus [url]</code></td></tr><tr><td style="text-align:left;"><code>curltime</code></td><td style="text-align:left;">HTTP 타이밍 메트릭 측정</td><td style="text-align:left;"><code>curltime [url]</code></td></tr><tr><td style="text-align:left;"><code>view-source</code></td><td style="text-align:left;">웹사이트 소스 코드 보기</td><td style="text-align:left;"><code>view-source URL</code></td></tr><tr><td style="text-align:left;"><code>whoisport</code></td><td style="text-align:left;">포트를 사용하는 프로세스 찾기</td><td style="text-align:left;"><code>whoisport PORT</code></td></tr></tbody></table><h3 id="파일-관리" tabindex="-1">파일 관리 <a class="header-anchor" href="#파일-관리" aria-label="Permalink to &quot;파일 관리&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">함수</th><th style="text-align:left;">설명</th><th style="text-align:left;">사용법</th></tr></thead><tbody><tr><td style="text-align:left;"><code>backup</code></td><td style="text-align:left;">타임스탬프 백업 생성</td><td style="text-align:left;"><code>backup [--max-size SIZE] [--keep N] &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>encode64</code> / <code>decode64</code></td><td style="text-align:left;">Base64 인코딩 및 디코딩</td><td style="text-align:left;"><code>encode64 &quot;string&quot;</code></td></tr><tr><td style="text-align:left;"><code>extract</code></td><td style="text-align:left;">압축 파일 형식 해제</td><td style="text-align:left;"><code>extract [file]</code></td></tr><tr><td style="text-align:left;"><code>hexdump</code></td><td style="text-align:left;">파일을 16진수 형식으로 표시</td><td style="text-align:left;"><code>hexdump [file] [lines]</code></td></tr><tr><td style="text-align:left;"><code>ren</code></td><td style="text-align:left;">확장자 일괄 변경</td><td style="text-align:left;"><code>ren OLD_EXT NEW_EXT</code></td></tr><tr><td style="text-align:left;"><code>size</code></td><td style="text-align:left;">파일 또는 디렉토리 크기 확인</td><td style="text-align:left;"><code>size [file/directory]</code></td></tr><tr><td style="text-align:left;"><code>zipf</code></td><td style="text-align:left;">ZIP 아카이브 생성</td><td style="text-align:left;"><code>zipf [folder]</code></td></tr></tbody></table><h3 id="파일-이름-지정" tabindex="-1">파일 이름 지정 <a class="header-anchor" href="#파일-이름-지정" aria-label="Permalink to &quot;파일 이름 지정&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">함수</th><th style="text-align:left;">설명</th><th style="text-align:left;">사용법</th></tr></thead><tbody><tr><td style="text-align:left;"><code>kebabcase</code></td><td style="text-align:left;">kebab-case로 변환</td><td style="text-align:left;"><code>kebabcase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>lowercase</code></td><td style="text-align:left;">소문자로 변환</td><td style="text-align:left;"><code>lowercase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>sentencecase</code></td><td style="text-align:left;">sentence case로 변환</td><td style="text-align:left;"><code>sentencecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>snakecase</code></td><td style="text-align:left;">snake_case로 변환</td><td style="text-align:left;"><code>snakecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>titlecase</code></td><td style="text-align:left;">Title Case로 변환</td><td style="text-align:left;"><code>titlecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>uppercase</code></td><td style="text-align:left;">대문자로 변환</td><td style="text-align:left;"><code>uppercase &lt;files...&gt;</code></td></tr></tbody></table><h3 id="시스템-유틸리티" tabindex="-1">시스템 유틸리티 <a class="header-anchor" href="#시스템-유틸리티" aria-label="Permalink to &quot;시스템 유틸리티&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">함수</th><th style="text-align:left;">설명</th><th style="text-align:left;">사용법</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine</code></td><td style="text-align:left;">시스템 절전 방지</td><td style="text-align:left;"><code>caffeine [command]</code></td></tr><tr><td style="text-align:left;"><code>environment</code></td><td style="text-align:left;">OS 환경 감지</td><td style="text-align:left;"><code>environment</code></td></tr><tr><td style="text-align:left;"><code>freespace</code></td><td style="text-align:left;">퍼지 가능한 디스크 공간 정리</td><td style="text-align:left;"><code>freespace [disk]</code></td></tr><tr><td style="text-align:left;"><code>hiddenfiles</code></td><td style="text-align:left;">Finder에서 숨김 파일 전환</td><td style="text-align:left;"><code>hiddenfiles [show|hide]</code></td></tr><tr><td style="text-align:left;"><code>hostinfo</code></td><td style="text-align:left;">호스트 정보 표시</td><td style="text-align:left;"><code>hostinfo</code></td></tr><tr><td style="text-align:left;"><code>hstats</code></td><td style="text-align:left;">명령 사용 통계 보기</td><td style="text-align:left;"><code>hstats</code></td></tr><tr><td style="text-align:left;"><code>last</code></td><td style="text-align:left;">최근 수정된 파일 나열</td><td style="text-align:left;"><code>last [minutes]</code></td></tr><tr><td style="text-align:left;"><code>logout</code></td><td style="text-align:left;">크로스 플랫폼 로그아웃</td><td style="text-align:left;"><code>logout [--force]</code></td></tr><tr><td style="text-align:left;"><code>myproc</code></td><td style="text-align:left;">사용자 프로세스 나열</td><td style="text-align:left;"><code>myproc</code></td></tr><tr><td style="text-align:left;"><code>stopwatch</code></td><td style="text-align:left;">터미널 스톱워치</td><td style="text-align:left;"><code>stopwatch</code></td></tr><tr><td style="text-align:left;"><code>sysinfo</code></td><td style="text-align:left;">시스템 정보 표시</td><td style="text-align:left;"><code>sysinfo</code></td></tr></tbody></table><h3 id="카페인-명령" tabindex="-1">카페인 명령 <a class="header-anchor" href="#카페인-명령" aria-label="Permalink to &quot;카페인 명령&quot;">​</a></h3><p>시스템 절전 또는 화면 보호기 활성화를 방지합니다.</p><table tabindex="0"><thead><tr><th style="text-align:left;">명령</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine daemon</code></td><td style="text-align:left;">카페인 데몬 시작</td></tr><tr><td style="text-align:left;"><code>caffeine status</code></td><td style="text-align:left;">데몬 실행 여부 확인</td></tr><tr><td style="text-align:left;"><code>caffeine start</code></td><td style="text-align:left;">화면 깨움 유지</td></tr><tr><td style="text-align:left;"><code>caffeine stop</code></td><td style="text-align:left;">화면 절전 허용</td></tr><tr><td style="text-align:left;"><code>caffeine toggle</code></td><td style="text-align:left;">화면 깨움 전환</td></tr><tr><td style="text-align:left;"><code>caffeine shutdown</code></td><td style="text-align:left;">데몬 종료</td></tr></tbody></table><p>macOS (네이티브 <code>caffeinate</code>), Linux (<code>xdg-screensaver</code>), Windows (PowerShell)에서 작동합니다.</p><h3 id="보안" tabindex="-1">보안 <a class="header-anchor" href="#보안" aria-label="Permalink to &quot;보안&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">함수</th><th style="text-align:left;">설명</th><th style="text-align:left;">사용법</th></tr></thead><tbody><tr><td style="text-align:left;"><code>genpass</code></td><td style="text-align:left;">강력한 비밀번호 생성</td><td style="text-align:left;"><code>genpass [num_blocks] [separator]</code></td></tr><tr><td style="text-align:left;"><code>keygen</code></td><td style="text-align:left;">SSH 키 쌍 생성</td><td style="text-align:left;"><code>keygen [name] [email] [type] [bits]</code></td></tr></tbody></table><h3 id="탐색" tabindex="-1">탐색 <a class="header-anchor" href="#탐색" aria-label="Permalink to &quot;탐색&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">함수</th><th style="text-align:left;">설명</th><th style="text-align:left;">사용법</th></tr></thead><tbody><tr><td style="text-align:left;"><code>cdls</code></td><td style="text-align:left;">디렉토리 변경 및 나열</td><td style="text-align:left;"><code>cdls [directory]</code></td></tr><tr><td style="text-align:left;"><code>goto</code></td><td style="text-align:left;">빠른 디렉토리 탐색</td><td style="text-align:left;"><code>goto [directory]</code></td></tr><tr><td style="text-align:left;"><code>mount_read_only</code></td><td style="text-align:left;">읽기 전용을 읽기-쓰기로 마운트</td><td style="text-align:left;"><code>mount_read_only [image]</code></td></tr><tr><td style="text-align:left;"><code>rd</code></td><td style="text-align:left;">디렉토리 제거</td><td style="text-align:left;"><code>rd [directory]</code></td></tr><tr><td style="text-align:left;"><code>remove_disk</code></td><td style="text-align:left;">안전하게 디스크 배출</td><td style="text-align:left;"><code>remove_disk [disk]</code></td></tr></tbody></table><h3 id="기타" tabindex="-1">기타 <a class="header-anchor" href="#기타" aria-label="Permalink to &quot;기타&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">함수</th><th style="text-align:left;">설명</th><th style="text-align:left;">사용법</th></tr></thead><tbody><tr><td style="text-align:left;"><code>matrix</code></td><td style="text-align:left;">터미널 Matrix 효과</td><td style="text-align:left;"><code>matrix [options]</code></td></tr><tr><td style="text-align:left;"><code>prependpath</code></td><td style="text-align:left;">PATH에 디렉토리 추가</td><td style="text-align:left;"><code>prependpath [directory]</code></td></tr><tr><td style="text-align:left;"><code>ql</code></td><td style="text-align:left;">macOS Quick Look에서 열기</td><td style="text-align:left;"><code>ql [file]</code></td></tr><tr><td style="text-align:left;"><code>vscode</code></td><td style="text-align:left;">VS Code에서 열기</td><td style="text-align:left;"><code>vscode [file]</code></td></tr></tbody></table><h2 id="호환성" tabindex="-1">호환성 <a class="header-anchor" href="#호환성" aria-label="Permalink to &quot;호환성&quot;">​</a></h2><ul><li><strong>macOS</strong> — macOS 전용 유틸리티와 함께 전체 지원</li><li><strong>Linux</strong> — 일반 배포판과 호환</li><li><strong>Windows</strong> — WSL, Cygwin, 또는 Git Bash를 통해 지원</li></ul><h2 id="도움말" tabindex="-1">도움말 <a class="header-anchor" href="#도움말" aria-label="Permalink to &quot;도움말&quot;">​</a></h2><p>각 함수에는 <code>--help</code>를 통한 문서가 포함되어 있습니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apihealth</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span></span></code></pre></div>',33)])])}const y=e(o,[["render",i]]);export{h as __pageData,y as default};
